import React, { useState, useEffect, useMemo } from 'react';
import axios from 'axios';

/**
 * ГЛАВНЫЙ КОМПОНЕНТ ПЛАТФОРМЫ PEX
 * Здесь сосредоточена вся логика: WebSocket, расчеты и интерфейс.
 */
function App() {
  // --- СОСТОЯНИЕ (STATE) ---
  const [activeTab, setActiveTab] = useState('market'); // Переключатель вкладок
  const [walletBalance, setWalletBalance] = useState(10000); // Баланс пользователя
  const [holdings, setHoldings] = useState([]); // Список купленных акций
  const [marketPrices, setMarketPrices] = useState({
    'DEV': 150.00,
    'PEX': 280.50,
    'AI': 420.00
  }); // Актуальные цены с биржи
  
  // JWT Токен для авторизации (замени на реальный после логина)
  const [token] = useState("YOUR_JWT_TOKEN_HERE");

  // --- РАБОТА С WEB SOCKET ---
  useEffect(() => {
    // Подключаемся к бэкенду. Передаем токен вторым параметром[cite: 1].
    const ws = new WebSocket('ws://localhost:5000', token);

    ws.onmessage = (event) => {
      const data = JSON.parse(event.data);
      // Если пришло обновление цены — обновляем объект цен[cite: 1]
      if (data.type === "TICKER_UPDATE") {
        setMarketPrices(prev => ({
          ...prev,
          [data.payload.ticker]: data.payload.price
        }));
      }
    };

    return () => ws.close(); // Закрываем соединение при выходе из приложения
  }, [token]);

  // --- РАСЧЕТ КАПИТАЛА (NET WORTH) ---
  // Формула: Баланс + Сумма(Кол-во акций * Текущая цена)[cite: 1]
  const netWorth = useMemo(() => {
    const assetsValue = holdings.reduce((total, stock) => {
      const currentPrice = marketPrices[stock.ticker] || 0;
      return total + (stock.amount * currentPrice);
    }, 0);
    return walletBalance + assetsValue;
  }, [walletBalance, holdings, marketPrices]);

  // --- ФУНКЦИИ ВЗАИМОДЕЙСТВИЯ ---
  const handleBuy = async (ticker) => {
    try {
      const response = await axios.post('http://localhost:5000/api/buy', 
        { ticker, amount: 1 }, // Покупаем по 1 штуке для простоты
        { headers: { Authorization: `Bearer ${token}` } }
      );
      // Обновляем данные из ответа сервера[cite: 1]
      setWalletBalance(response.data.balance);
      setHoldings(response.data.holdings);
    } catch (error) {
      alert("Ошибка при покупке. Проверьте баланс или соединение.");
    }
  };

  // --- ИНТЕРФЕЙС (UI) ---
  return (
    <div style={styles.container}>
      {/* Шапка с балансом */}
      <header style={styles.header}>
        <h1>PEX Exchange</h1>
        <div style={styles.balanceCard}>
          <div>Доступно: <strong>${walletBalance.toLocaleString()}</strong></div>
          <div style={{ color: '#2ecc71' }}>
            Общий капитал: <strong>${netWorth.toLocaleString()}</strong>
          </div>
        </div>
      </header>

      {/* Навигация */}
      <nav style={styles.nav}>
        <button 
          onClick={() => setActiveTab('market')}
          style={activeTab === 'market' ? styles.activeBtn : styles.btn}>
          Рынок акций
        </button>
        <button 
          onClick={() => setActiveTab('portfolio')}
          style={activeTab === 'portfolio' ? styles.activeBtn : styles.btn}>
          Мой портфель ({holdings.length})
        </button>
      </nav>

      {/* Контент вкладок */}
      <main style={styles.main}>
        {activeTab === 'market' ? (
          <section>
            <h2>Котировки в реальном времени</h2>
            <div style={styles.grid}>
              {Object.entries(marketPrices).map(([ticker, price]) => (
                <div key={ticker} style={styles.card}>
                  <h3>{ticker}</h3>
                  <p style={styles.price}>${price.toFixed(2)}</p>
                  <button onClick={() => handleBuy(ticker)} style={styles.buyBtn}>
                    Купить 1 ед.
                  </button>
                </div>
              ))}
            </div>
          </section>
        ) : (
          <section>
            <h2>Ваши активы</h2>
            {holdings.length === 0 ? (
              <p>Вы еще не приобрели ни одной акции.</p>
            ) : (
              <table style={styles.table}>
                <thead>
                  <tr>
                    <th>Тикер</th>
                    <th>Количество</th>
                    <th>Тек. цена</th>
                    <th>Стоимость</th>
                  </tr>
                </thead>
                <tbody>
                  {holdings.map(h => (
                    <tr key={h.ticker}>
                      <td>{h.ticker}</td>
                      <td>{h.amount}</td>
                      <td>${(marketPrices[h.ticker] || 0).toFixed(2)}</td>
                      <td>${(h.amount * (marketPrices[h.ticker] || 0)).toFixed(2)}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            )}
          </section>
        )}
      </main>
    </div>
  );
}

const styles = {
  container: { maxWidth: '900px', margin: '0 auto', fontFamily: 'Segoe UI, sans-serif', color: '#2c3e50' },
  header: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '20px', borderBottom: '1px solid #eee' },
  balanceCard: { textAlign: 'right', fontSize: '1.1rem' },
  nav: { display: 'flex', gap: '10px', padding: '20px' },
  btn: { padding: '10px 20px', cursor: 'pointer', border: '1px solid #ddd', background: '#fff', borderRadius: '5px' },
  activeBtn: { padding: '10px 20px', cursor: 'pointer', border: 'none', background: '#3498db', color: '#fff', borderRadius: '5px' },
  main: { padding: '0 20px' },
  grid: { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(200px, 1fr))', gap: '20px' },
  card: { padding: '20px', border: '1px solid #eee', borderRadius: '10px', textAlign: 'center', boxShadow: '0 2px 5px rgba(0,0,0,0.05)' },
  price: { fontSize: '1.5rem', fontWeight: 'bold', color: '#e74c3c' },
  buyBtn: { width: '100%', padding: '8px', background: '#2ecc71', color: '#fff', border: 'none', borderRadius: '5px', cursor: 'pointer' },
  table: { width: '100%', borderCollapse: 'collapse', marginTop: '10px' }
};

export default App;
